INSERT INTO public."Evenimente" (id_event, name, description, location, date, organiser, imgpath, city, type, stoc_bilete, id_user) VALUES (2, E'Garden of Lights – Small World', E'Expoziţia immersivă „Garden of Lights – Small World” transformă grădina într‑o lume de poveste între 24 octombrie 2025 şi 1 martie 2026, cu instalaţii luminoase, tuneluri tematice şi zone foto interactive — o experienţă dedicată întregii familii.', E'Grădina Botanică „Dimitrie Brândză”, Șos. Cotroceni 32, Sector 6, București', E'2025-10-24 18:00:00+00', E'SMART Event Marketing', E'https://frglmxyomjqspveyszya.supabase.co/storage/v1/object/public/event-images/garden_of_lights.png', E'București', E'fizic', 500, NULL);
INSERT INTO public."Evenimente" (id_event, name, description, location, date, organiser, imgpath, city, type, stoc_bilete, id_user) VALUES (11, E'Turneu Bitză – 20 de ani de la Un Înger', E'Concert aniversar al artistului Bitză, ce marchează 20 de ani de la hitul „Un Înger”. Un show cu decor special, o selecţie de piese din întreaga carieră şi invitaţi surpriză pentru fanii rap/hip‑hop.', E'BT Arena, Str. Uzinei Electrice 4, Cluj-Napoca, Județ Cluj', E'2025-11-30 20:00:00+00', E'Bitză', E'https://frglmxyomjqspveyszya.supabase.co/storage/v1/object/public/event-images/bitza.png', E'Cluj-Napoca', E'fizic', 700, NULL);
INSERT INTO public."Evenimente" (id_event, name, description, location, date, organiser, imgpath, city, type, stoc_bilete, id_user) VALUES (10, E'CODRU Festival 2026', E'Festivalul „CODRU 2026” combină muzică live, artă contemporană şi experienţe outdoor în Timişoara – o ocazie de a celebra creativitatea, comunitatea şi muzica într‑un cadru alternativ.', E'Pădurea Bistra, Str. Aleea Codrului, Timișoara, Județ Timiș', E'2026-08-15 12:00:00+00', E'CODRU Org', E'https://frglmxyomjqspveyszya.supabase.co/storage/v1/object/public/event-images/codru.png', E'Timișoara', E'fizic', 5000, NULL);
INSERT INTO public."Evenimente" (id_event, name, description, location, date, organiser, imgpath, city, type, stoc_bilete, id_user) VALUES (18, E'Concert Vama la Hard Rock Cafe', E'Trupa Vama urcă pe scenă la Hard Rock Cafe într‑un concert intim, dar cu impact – hituri pop‑rock, conexiune cu publicul şi atmosferă de club-rock.', E'Hard Rock Cafe, Șos. Kiseleff 32, Sector 1, București', E'2025-11-25 20:00:00+00', E'Vama', E'https://frglmxyomjqspveyszya.supabase.co/storage/v1/object/public/event-images/concert_vama.png', E'București', E'fizic', 500, NULL);
INSERT INTO public."Evenimente" (id_event, name, description, location, date, organiser, imgpath, city, type, stoc_bilete, id_user) VALUES (13, E'Turneu Fuego – Iarna Colindelor', E'Concertul susţinut de artistul Fuego aduce colinde, poveşti muzicale şi momente solemne de reculegere – un spectacol de iarnă pentru toată familia, într‑un decor festiv.', E'Casa de Cultură a Sindicatelor, Str. I.C. Brătianu 1, Târgoviște', E'2025-12-10 19:00:00+00', E'Fuego', E'https://frglmxyomjqspveyszya.supabase.co/storage/v1/object/public/event-images/fuego.png', E'Târgoviște', E'fizic', 900, NULL);
