INSERT INTO public."Evenimente" (id_event, name, description, location, date, organiser, imgpath, city, type, stoc_bilete, id_user) VALUES (12, E'Turneu Tudor Gheorghe – The Best of de Toamnă', E'Evenimentul îl are ca protagonist pe reputatul artist Tudor Gheorghe într‑o selecţie „The Best of” ce cuprinde piese reprezentative din cariera sa. Un recital dedicat melomanilor şi publicului adult, într‑o atmosferă intimă de toamnă.', E'Casa de Cultură a Sindicatelor, Bd. Victoriei 10, Sibiu', E'2025-11-15 19:00:00+00', E'Tudor Gheorghe', E'https://frglmxyomjqspveyszya.supabase.co/storage/v1/object/public/event-images/tudor_gheorghe.png', E'Sibiu', E'fizic', 900, NULL);
INSERT INTO public."Evenimente" (id_event, name, description, location, date, organiser, imgpath, city, type, stoc_bilete, id_user) VALUES (8, E'Turneu Regal vienez – Concert extraordinar', E'Turneul „Regal vienez” reuneşte muzicieni şi orchestră tradiţională vieneză într‑o seară de valsuri, polci şi marşuri clasice, în stilul balului imperial de la Viena — o experienţă elegantă de Crăciun.', E'Ateneul Român, Str. Benjamin Franklin 1-3, Sector 1, București', E'2025-12-21 19:00:00+00', E'Regal Viena', E'https://frglmxyomjqspveyszya.supabase.co/storage/v1/object/public/event-images/turneu_regal_vienez.png', E'București', E'fizic', 800, NULL);
